css:
@page { size: A4; margin: 0; }

body {
  margin: 0; padding: 22mm 28mm;
  background: #faf7f2; color: #14110e;
  font-family: 'Helvetica', 'Arial', sans-serif;
  -webkit-print-color-adjust: exact; print-color-adjust: exact;
}
.num { font-variant-numeric: tabular-nums; }
.doc-header { display: block; margin: 0; }

/* Centered masthead */
.lx-head { text-align: center; }
.lx-mark { height: 9mm; width: 9mm; display: inline-block; margin-bottom: 4mm; }
.lx-wordmark { font-family: 'Georgia', 'Times New Roman', serif; font-size: 25pt; font-weight: 400; letter-spacing: 0.32em; text-transform: uppercase; text-indent: 0.32em; }
.lx-tagline { font-size: 8pt; letter-spacing: 0.3em; text-transform: uppercase; color: #9c7c46; margin-top: 2.5mm; text-indent: 0.3em; }

.lx-divider { height: 1px; background: #14110e; margin: 9mm 0; }
.lx-divider--thin { background: #d8d0c2; margin: 6mm 0 4mm; }

/* Title block */
.lx-titleblock { text-align: center; margin-bottom: 11mm; }
.lx-eyebrow { font-size: 8.5pt; letter-spacing: 0.34em; text-transform: uppercase; color: #9c7c46; font-weight: 700; text-indent: 0.34em; }
.lx-docno { font-family: 'Georgia', 'Times New Roman', serif; font-size: 21pt; font-weight: 400; letter-spacing: 0.06em; margin: 3mm 0 0; }
.lx-statement { font-size: 10.5pt; line-height: 1.7; color: #4a443a; max-width: 120mm; margin: 5mm auto 0; }

/* Meta */
.lx-meta { display: flex; gap: 8mm; padding: 5mm 0; border-top: 1px solid #e0d8ca; border-bottom: 1px solid #e0d8ca; margin-bottom: 9mm; }
.lx-meta__col { flex: 1 1 0; }
.lx-meta__col > div { line-height: 1.55; font-size: 9.5pt; }
.lx-meta__col--c { text-align: center; }
.lx-meta__col--r { text-align: right; }
.lx-label { font-size: 7pt; letter-spacing: 0.2em; text-transform: uppercase; color: #9c7c46; font-weight: 700; margin-bottom: 2mm; }
.lx-strong { font-weight: 700; }
.lx-dim { color: #8a8170; }

/* Items */
.lx-items { width: 100%; border-collapse: collapse; margin-bottom: 10mm; }
.lx-items td { padding: 4mm 0; border-bottom: 1px solid #e8e1d4; vertical-align: baseline; }
.lx-iname .lx-n { font-family: 'Georgia', 'Times New Roman', serif; font-size: 13pt; display: block; }
.lx-iname .lx-d { font-size: 9pt; color: #8a8170; margin-top: 1.2mm; display: block; letter-spacing: 0.02em; }
.lx-iqty { width: 22mm; text-align: right; color: #8a8170; font-size: 10pt; }
.lx-iamt { width: 34mm; text-align: right; font-size: 12pt; }

/* Total — centered statement */
.lx-total { text-align: center; margin: 12mm 0; }
.lx-total__label { font-size: 8.5pt; letter-spacing: 0.3em; text-transform: uppercase; color: #9c7c46; font-weight: 700; text-indent: 0.3em; }
.lx-total__amt { font-family: 'Georgia', 'Times New Roman', serif; font-size: 38pt; font-weight: 400; letter-spacing: 0.01em; margin: 3mm 0 0; }
.lx-total__note { font-size: 8.5pt; color: #8a8170; margin-top: 4mm; }

/* Footer */
.lx-foot { margin-top: 14mm; }
.lx-foot__row { display: flex; justify-content: space-between; font-size: 7.5pt; letter-spacing: 0.1em; text-transform: uppercase; color: #8a8170; }
.lx-foot__legal { text-align: center; font-size: 7pt; color: #8a8170; line-height: 1.7; letter-spacing: 0.02em; }

.lx-total__break { font-size: 9pt; color: #6c685e; margin-top: 2.5mm; }
